"python3 -c \"\nimport json\nwith open('/Users/rohan/.gemini/antigravity-ide/brain/7760f898-6df2-4143-a541-ee055682e01e/.system_generated/logs/transcript.jsonl', 'r') as f:\n    for line in f:\n        if '_modal_daily_menu' in line:\n            try:\n                data = json.loads(line)\n                # Check tool calls\n                if 'tool_calls' in data:\n                    for tc in data['tool_calls']:\n                        if 'ReplacementContent' in tc.get('args', {}):\n                            content = tc['args']['ReplacementContent']\n                            if 'def _modal_daily_menu' in content:\n                                print('FOUND tool call! Length:', len(content))\n                                # Save to a temporary file\n                                with open('recovered_modal.py', 'w') as out:\n                                    out.write(content)\n                                print('Saved to recovered_modal.py')\n            except Exception as e:\n                pass\n\""